31: /**
32:  * A {@link Trigger} that continuously fires based on a given time interval. This fires based on
33:  * {@link org.apache.flink.streaming.api.watermark.Watermark Watermarks}.
34:  *
35:  * @see org.apache.flink.streaming.api.watermark.Watermark
36:  * @param <W> The type of {@link Window Windows} on which this trigger can operate.
37:  */
38: @PublicEvolving
39: public class ContinuousEventTimeTrigger<W extends Window> extends Trigger<Object, W> {
40:     private static final long serialVersionUID = 1L;
41: 
42:     private final long interval;
43: 
44:     /** When merging we take the lowest of all fire timestamps as the new fire timestamp. */
45:     private final ReducingStateDescriptor<Long> stateDesc =
46:             new ReducingStateDescriptor<>("fire-time", new Min(), LongSerializer.INSTANCE);
47: 
48:     private ContinuousEventTimeTrigger(long interval) {
49:         this.interval = interval;
50:     }
51: 
52:     @Override
53:     public TriggerResult onElement(Object element, long timestamp, W window, TriggerContext ctx)
54:             throws Exception {
55: 
56:         if (window.maxTimestamp() <= ctx.getCurrentWatermark()) {
57:             // if the watermark is already past the window fire immediately
58:             return TriggerResult.FIRE;
59:         } else {
60:             ctx.registerEventTimeTimer(window.maxTimestamp());
61:         }
62: 
63:         ReducingState<Long> fireTimestampState = ctx.getPartitionedState(stateDesc);
64:         if (fireTimestampState.get() == null) {
65:             registerNextFireTimestamp(
66:                     timestamp - (timestamp % interval), window, ctx, fireTimestampState);
67:         }
68: 
69:         return TriggerResult.CONTINUE;
70:     }
71: 
72:     @Override
73:     public TriggerResult onEventTime(long time, W window, TriggerContext ctx) throws Exception {
74: 
75:         if (time == window.maxTimestamp()) {
76:             return TriggerResult.FIRE;
77:         }
78: 
79:         ReducingState<Long> fireTimestampState = ctx.getPartitionedState(stateDesc);
80: 
81:         Long fireTimestamp = fireTimestampState.get();
82: 
83:         if (fireTimestamp != null && fireTimestamp == time) {
84:             fireTimestampState.clear();
85:             registerNextFireTimestamp(time, window, ctx, fireTimestampState);
86:             return TriggerResult.FIRE;
87:         }
88: 
89:         return TriggerResult.CONTINUE;
90:     }
91: 
92:     @Override
93:     public TriggerResult onProcessingTime(long time, W window, TriggerContext ctx)
94:             throws Exception {
95:         return TriggerResult.CONTINUE;
96:     }
97: 
98:     @Override
99:     public void clear(W window, TriggerContext ctx) throws Exception {
100:         ReducingState<Long> fireTimestamp = ctx.getPartitionedState(stateDesc);
101:         Long timestamp = fireTimestamp.get();
102:         if (timestamp != null) {
103:             ctx.deleteEventTimeTimer(timestamp);
104:             fireTimestamp.clear();
105:         }
106:     }
107: 
108:     @Override
109:     public boolean canMerge() {
110:         return true;
111:     }
112: 
113:     @Override
114:     public void onMerge(W window, OnMergeContext ctx) throws Exception {
115:         ctx.mergePartitionedState(stateDesc);
116:         Long nextFireTimestamp = ctx.getPartitionedState(stateDesc).get();
117:         if (nextFireTimestamp != null) {
118:             ctx.registerEventTimeTimer(nextFireTimestamp);
119:         }
120:     }
121: 
122:     @Override
123:     public String toString() {
124:         return "ContinuousEventTimeTrigger(" + interval + ")";
125:     }
126: 
127:     @VisibleForTesting
128:     public long getInterval() {
129:         return interval;
130:     }
131: 
132:     /**
133:      * Creates a trigger that continuously fires based on the given interval.
134:      *
135:      * @param interval The time interval at which to fire.
136:      * @param <W> The type of {@link Window Windows} on which this trigger can operate.
137:      */
138:     public static <W extends Window> ContinuousEventTimeTrigger<W> of(Duration interval) {
139:         return new ContinuousEventTimeTrigger<>(interval.toMillis());
140:     }
141: 
142:     private static class Min implements ReduceFunction<Long> {
143:         private static final long serialVersionUID = 1L;
144: 
145:         @Override
146:         public Long reduce(Long value1, Long value2) throws Exception {
147:             return Math.min(value1, value2);
148:         }
149:     }
150: 
151:     private void registerNextFireTimestamp(
152:             long time, W window, TriggerContext ctx, ReducingState<Long> fireTimestampState)
153:             throws Exception {
154:         long nextFireTimestamp = Math.min(time + interval, window.maxTimestamp());
155:         fireTimestampState.add(nextFireTimestamp);
156:         ctx.registerEventTimeTimer(nextFireTimestamp);
157:     }
158: }
