40: /**
41:  * A {@link Window} that represents a time interval from {@code start} (inclusive) to {@code end}
42:  * (exclusive).
43:  */
44: @PublicEvolving
45: public class TimeWindow extends Window {
46: 
47:     private final long start;
48:     private final long end;
49: 
50:     public TimeWindow(long start, long end) {
51:         this.start = start;
52:         this.end = end;
53:     }
54: 
55:     /**
56:      * Gets the starting timestamp of the window. This is the first timestamp that belongs to this
57:      * window.
58:      *
59:      * @return The starting timestamp of this window.
60:      */
61:     public long getStart() {
62:         return start;
63:     }
64: 
65:     /**
66:      * Gets the end timestamp of this window. The end timestamp is exclusive, meaning it is the
67:      * first timestamp that does not belong to this window any more.
68:      *
69:      * @return The exclusive end timestamp of this window.
70:      */
71:     public long getEnd() {
72:         return end;
73:     }
74: 
75:     /**
76:      * Gets the largest timestamp that still belongs to this window.
77:      *
78:      * <p>This timestamp is identical to {@code getEnd() - 1}.
79:      *
80:      * @return The largest timestamp that still belongs to this window.
81:      * @see #getEnd()
82:      */
83:     @Override
84:     public long maxTimestamp() {
85:         return end - 1;
86:     }
87: 
88:     @Override
89:     public boolean equals(Object o) {
90:         if (this == o) {
91:             return true;
92:         }
93:         if (o == null || getClass() != o.getClass()) {
94:             return false;
95:         }
96: 
97:         TimeWindow window = (TimeWindow) o;
98: 
99:         return end == window.end && start == window.start;
100:     }
