102:     @Override
103:     public int hashCode() {
104:         return MathUtils.longToIntWithBitMixing(start + end);
105:     }
106: 
107:     @Override
108:     public String toString() {
109:         return "TimeWindow{" + "start=" + start + ", end=" + end + '}';
110:     }
111: 
112:     /**
113:      * Returns {@code true} if this window intersects the given window or if this window is just
114:      * after or before the given window.
115:      */
116:     public boolean intersects(TimeWindow other) {
117:         return this.start <= other.end && this.end >= other.start;
118:     }
119: 
120:     /** Returns the minimal window covers both this window and the given window. */
121:     public TimeWindow cover(TimeWindow other) {
122:         return new TimeWindow(Math.min(start, other.start), Math.max(end, other.end));
123:     }
