256:     /**
257:      * Method to get the window start for a timestamp.
258:      *
259:      * @param timestamp epoch millisecond to get the window start.
260:      * @param offset The offset which window start would be shifted by.
261:      * @param windowSize The size of the generated windows.
262:      * @return window start
263:      */
264:     public static long getWindowStartWithOffset(long timestamp, long offset, long windowSize) {
265:         final long remainder = (timestamp - offset) % windowSize;
266:         // handle both positive and negative cases
267:         if (remainder < 0) {
268:             return timestamp - (remainder + windowSize);
269:         } else {
270:             return timestamp - remainder;
271:         }
272:     }
273: }
